; ポラリスの神殿

name = ポラリスの神殿
insideName = Temple
level = 4
bgm = shrine
margin = 1
shadow = dark
sky = black
roof = marble
blank = rock
outfield = marble

; パーツ画像
━ = marble
　 = marble
〰 = water
☖ = arch
☗ = exit
⧻ = stonegate
︻ = panel
⑹ = monument

; 敵情報
maxGroups = 2
monsters = コボルド,オーク
traps = 石つぶて,毒針,しびれ針

; 移動ポイント
(A) = map:デールコインの森, x:21, y:1, way:n, symbol:exit ,ask:Leave the dungeon?
(B) = x:3, y:2
(C) = x:3, y:14

; 宝箱
box[1] = 毒針,金貨（中）,ハイポーション,モーニングスター,聖なるローブ,バルキリーの書

